import fs from 'node:fs';
import path from 'node:path';
import process from 'node:process';

const root = process.cwd();
const migrationsDir = path.join(root, 'supabase', 'migrations');
const outputPath = path.join(root, 'supabase', 'setup.sql');

function printHelp() {
  console.log(`CoupleSync Supabase SQL bundle

Usage:
  npm run sql:supabase

This combines supabase/migrations/*.sql in filename order into:
  supabase/setup.sql

Use the bundle when pasting SQL into the Supabase dashboard SQL Editor.`);
}

if (process.argv.includes('--help') || process.argv.includes('-h')) {
  printHelp();
  process.exit(0);
}

if (!fs.existsSync(migrationsDir)) {
  console.error('Missing supabase/migrations directory.');
  process.exit(1);
}

const migrationFiles = fs.readdirSync(migrationsDir)
  .filter(file => file.endsWith('.sql'))
  .sort();

if (migrationFiles.length === 0) {
  console.error('No SQL migration files found under supabase/migrations.');
  process.exit(1);
}

const sections = migrationFiles.map(file => {
  const absolutePath = path.join(migrationsDir, file);
  const sql = fs.readFileSync(absolutePath, 'utf8').trimEnd();
  return [
    `-- ============================================================`,
    `-- ${file}`,
    `-- ============================================================`,
    sql,
  ].join('\n');
});

const bundle = [
  `-- CoupleSync Supabase setup bundle.`,
  `-- Generated by npm run sql:supabase.`,
  `-- Source files are combined from supabase/migrations in filename order.`,
  ``,
  sections.join('\n\n'),
  ``,
].join('\n');

fs.writeFileSync(outputPath, bundle);

console.log(`Wrote ${path.relative(root, outputPath)} from ${migrationFiles.length} migration file${migrationFiles.length === 1 ? '' : 's'}:`);
migrationFiles.forEach(file => console.log(`- ${file}`));
